  shell.set_command_execute_function(shell_cmd_id,
                                     write_fabric_bitstream_template<T>);

  /* Add command dependency to the Shell */
  shell.set_command_dependency(shell_cmd_id, dependent_cmds);

  return shell_cmd_id;
